14	def _image_path_to_url(path: str) -> str:
15	    if path.startswith("http://") or path.startswith("https://"):
16	        return path
17	    normalized = path.replace("\\", "/")
18	    if normalized.startswith("/data/"):
19	        url = normalized
20	    elif normalized.startswith("data/"):
21	        url = "/" + normalized
22	    else:
23	        base = Path("data").resolve()
24	        try:
25	            rel = Path(path).resolve().relative_to(base)
26	            url = "/data/" + rel.as_posix()
27	        except ValueError:
28	            url = normalized
29	    return quote(url, safe="/:")
