6	SPEECH_SUPPORT_HTML = """
7	<script>
8	(() => {
9	  const SpeechRecognition = window.SpeechRecognition || window.webkitSpeechRecognition;
10	  window.__speech = window.__speech || {};
11	  window.__speech.supported = !!SpeechRecognition;
12	  window.__speech._recognition = null;
13	  window.__speech._resolve = null;
14	  window.__speech._reject = null;
15	  window.__speech._inputSelector = '.stt-input input';
16	
17	  window.__speech._setInputValue = (value) => {
18	    const input = document.querySelector(window.__speech._inputSelector);
19	    if (!input) return;
20	    input.value = value;
21	    input.dispatchEvent(new Event('input', { bubbles: true }));
22	  };
23	
24	  window.__speech.start = () => {
25	    return new Promise((resolve, reject) => {
26	      const SR = window.SpeechRecognition || window.webkitSpeechRecognition;
27	      if (!SR) {
28	        reject('SpeechRecognition not supported');
29	        return;
30	      }
31	
32	      if (window.__speech._recognition) {
33	        try { window.__speech._recognition.stop(); } catch (e) { /* no-op */ }
34	      }
35	
36	      const recognition = new SR();
37	      window.__speech._recognition = recognition;
38	      window.__speech._resolve = resolve;
39	      window.__speech._reject = reject;
40	
41	      recognition.lang = navigator.language || 'en-US';
42	      recognition.interimResults = true;
43	      recognition.continuous = false;
44	
45	      let finalTranscript = '';
46	      recognition.onresult = (event) => {
47	        let interim = '';
48	        for (let i = event.resultIndex; i < event.results.length; i++) {
49	          const result = event.results[i];
50	          const transcript = result[0].transcript;
51	          if (result.isFinal) finalTranscript += transcript;
52	          else interim += transcript;
53	        }
54	        const combined = (finalTranscript + ' ' + interim).trim();
55	        window.__speech._setInputValue(combined);
56	      };
57	
58	      recognition.onerror = (event) => {
59	        const err = event.error || 'speech_recognition_error';
60	        if (window.__speech._reject) window.__speech._reject(err);
61	        window.__speech._reject = null;
62	        window.__speech._resolve = null;
63	      };
64	
65	      recognition.onend = () => {
66	        if (window.__speech._resolve) window.__speech._resolve(finalTranscript.trim());
67	        window.__speech._resolve = null;
68	        window.__speech._reject = null;
69	      };
70	
71	      recognition.start();
72	    });
73	  };
74	
75	  window.__speech.stop = () => {
76	    try {
77	      if (window.__speech._recognition) window.__speech._recognition.stop();
78	    } catch (e) { /* no-op */ }
79	  };
80	
81	  window.__speech.speak = (text) => {
82	    if (!('speechSynthesis' in window)) return false;
83	    if (!text) return false;
84	    const utterance = new SpeechSynthesisUtterance(text);
85	    utterance.lang = navigator.language || 'en-US';
86	    window.speechSynthesis.cancel();
87	    window.speechSynthesis.speak(utterance);
88	    return true;
89	  };
90	
91	  window.__speech.cancel = () => {
92	    if ('speechSynthesis' in window) window.speechSynthesis.cancel();
93	  };
94	})();
95	</script>
96	"""
